const raw = $input.first().json;
const body = raw.body || raw;
const fecha = new Date(body.fecha).toLocaleDateString('es-ES', {
  day: 'numeric', month: 'long', year: 'numeric'
});

// Convertir markdown básico a HTML
function markdownToHtml(text) {
  if (!text) return '';
  return text
    .replace(/## (.*)/g, '<h3 style="color:#4a7c59;margin:24px 0 8px;">$1</h3>')
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/^- (.*)/gm, '<li>$1</li>')
    .replace(/^(\d+)\. (.*)/gm, '<li>$2</li>')
    .replace(/(<li>.*<\/li>)/gs, '<ul style="margin:8px 0;padding-left:20px;">$1</ul>')
    .replace(/\n\n/g, '<br>')
}

const calorias = body.calorias_total ? Math.round(body.calorias_total) : null;
const notasHtml = markdownToHtml(body.notas_ia);

const html = `
<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; padding: 40px; color: #2d3a1f; max-width: 700px; margin: 0 auto; }
    h1 { color: #4a7c59; font-size: 28px; margin-bottom: 4px; }
    .subtitle { color: #7a8c6a; font-size: 14px; margin-bottom: 32px; }
    .section { background: #f5f0e8; border-radius: 12px; padding: 20px; margin-bottom: 20px; }
    .section h2 { font-size: 16px; color: #4a7c59; margin: 0 0 12px; }
    .section p { margin: 0; font-size: 14px; line-height: 1.6; }
    .kcal { font-size: 32px; font-weight: bold; color: #4a7c59; }
    .plan { font-size: 14px; line-height: 1.8; }
    .plan h3 { color: #4a7c59; }
    .plan ul { margin: 4px 0; padding-left: 20px; }
    .plan li { margin-bottom: 4px; }
    .footer { margin-top: 40px; font-size: 12px; color: #999; text-align: center; }
  </style>
</head>
<body>
  <h1>🐾 Plan Nutricional Kahu</h1>
  <div class="subtitle">Generado el ${fecha} · ${body.nombre_perro || body.mascota_nombre || 'Tu mascota'}</div>

  ${calorias ? `
  <div class="section">
    <h2>Calorías totales</h2>
    <span class="kcal">${calorias} kcal</span>
  </div>` : ''}

  <div class="section">
    <h2>Ingredientes</h2>
    <p>${body.ingredientes}</p>
  </div>

  ${body.proporciones ? `
  <div class="section">
    <h2>Proporciones</h2>
    <p>${body.proporciones}</p>
  </div>` : ''}

  ${body.notas_ia ? `
  <div class="section">
    <h2>Plan detallado</h2>
    <div class="plan">${notasHtml}</div>
  </div>` : ''}

  <div class="footer">Generado por Kahu · kahuappcontact@gmail.com</div>
</body>
</html>
`;
return [{ json: { html, body } }];
